      </div>
    </div>
    <loader v-if="loading" />
    <div  v-else class="add_tarozi_main px-3">
      <div class="add_tarozi_item rounded card mt-3 px-2 pt-3 pb-2" v-for="(item, index) in product_list" :key="index">
        <div class="row">
          <div class="col-3">
