            </mdb-btn>
            <mdb-btn class="m-0 py-1 px-3 ml-2" @click="openCameraSnapshot(index)"
                style="font-size: 12px;" color="info"
                size="sm"><mdb-icon fas icon="video"></mdb-icon>
            </mdb-btn>
            <mdb-btn v-if="product_list.length>1" class="m-0 py-1 px-3 ml-2" @click="delItem(index)"
                style="font-size: 12px;" color="danger"
                size="sm"><mdb-icon fas  icon="trash"></mdb-icon>
            </mdb-btn>
          </div>
        </div>
        <div class="photo mt-0 d-flex justify-content-start" v-if="item.image_first_pull">
          <img :src="hostname + item.image_first_pull" width="180" alt="" @click="$imageModal.open(hostname + item.image_first_pull)" class="shadow border rounded">
        </div>
      </div>
    </div>
    <div class="add_container text-right border-top mt-3 mx-3 pt-1">
      <mdb-btn 
        v-if="hasAnyImage" 
        class="m-0 py-2 px-4" 
        @click="save_items"
        style="font-size: 8px;" 
        color="success"
        size="sm"
      >
        <mdb-icon fas class="mr-1"  icon="check"></mdb-icon> {{$t('save')}}
      </mdb-btn>
    </div>
    <modal-train  :show="add_client_show" headerbackColor="white"  titlecolor="black" :title="$t('show_davernis')" 
      @close="add_client_show = false" width="85%">
        <template v-slot:body>
          <addClientNew @close="add_client_show = false"  @close_data="close_clientAdd" ref="addClientrefs">
          </addClientNew>
        </template>
    </modal-train>
    <modal-train  :show="add_ticket_show" headerbackColor="white"  titlecolor="black" :title="$t('add_ticket')" 
      @close="add_ticket_show = false" width="50%">
        <template v-slot:body>
          <div class="ticket_modal_content p-3">
            <div class="form-group mb-1">
              <label style="font-size: 13px; margin-bottom: 0px;">{{$t('ticket_number')}} <span class="text-danger">*</span></label>
              <mdb-input class="m-0" v-model="ticket_data.ticket_number" 
                :placeholder="$t('ticket_number')" size="md"
                outline group type="text" validate error="wrong" success="right"/>
            </div>
            <div class="form-group mb-1">
              <label style="font-size: 13px; margin-bottom: 0px;">{{$t('massa')}} <span class="text-danger">*</span></label>
              <input 
                class="ticket_number_input" 
                v-model="ticket_data.massa_display" 
                @input="formatMassa"
                @focus="clearZero('massa')"
                :placeholder="$t('massa')"
                type="text"
              />
            </div>
            <div class="form-group mb-1">
              <label style="font-size: 13px; margin-bottom: 0px;">{{$t('price')}}</label>
              <input 
                class="ticket_number_input" 
                v-model="ticket_data.price_display" 
                @input="formatPrice"
                @focus="clearZero('price')"
                :placeholder="$t('price')"
                type="text"
              />
            </div>
            <div class="form-group mb-1">
              <label style="font-size: 13px; margin-bottom: 0px;">{{$t('total_price')}}</label>
              <input 
                class="ticket_number_input" 
                v-model="ticket_data.total_price_display" 
                @input="formatTotalPrice"
                @focus="clearZero('total_price')"
                :placeholder="$t('total_price')"
