              />
            </div>
            <div class="form-group mb-1">
              <label style="font-size: 13px; margin-bottom: 0px;">{{$t('organization_name')}}</label>
              <mdb-input class="m-0" v-model="ticket_data.organization_name" 
                :placeholder="$t('organization_name')" size="md"
                outline group type="text" validate error="wrong" success="right"/>
            </div>
            <div class="form-group">
              <label style="font-size: 13px; margin-bottom: 0px;">{{$t('tegirmon_hisob')}}</label>
              <erpSelectHisoblar
                :options="hisob_list"
                @select="selectHisob"
                :selected="ticket_data.hisob_name"
                :label="$t('tegirmon_hisob')"
                size="sm"
                class="bg-white mb-0"
                url="/TegirmonHisoblar/getPagination?page=0&size=100"
              />
            </div>
            <div class="form-group">
              <label style="font-size: 13px; margin-bottom: 0px;">{{$t('note')}}</label>
              <mdb-input class="m-0" v-model="ticket_data.note" 
                :placeholder="$t('note')" size="md"
                outline group type="textarea" validate error="wrong" success="right"/>
            </div>
            <div class="text-right mt-3">
              <mdb-btn class="m-0 py-2 px-4 mr-2" @click="add_ticket_show = false"
                  style="font-size: 12px;" color="secondary"
                  size="sm">{{$t('cancel')}}
              </mdb-btn>
              <mdb-btn class="m-0 py-2 px-4" @click="save_ticket"
                  style="font-size: 12px;" color="success"
                  size="sm"><mdb-icon fas class="mr-1"  icon="check"></mdb-icon> {{$t('save')}}
              </mdb-btn>
            </div>
          </div>
        </template>
    </modal-train>
    <webcam  v-show="showPhoto" @getPhotosub="takePhoto" ref="camera_component"/>
    <massage_box :hide="modal_status" :detail_info="modal_info"
      :m_text="$t('Failed_to_add')" @to_hide_modal="modal_status= false"/>
      <Toast ref="message"></Toast>
  </div>
</template>

<script>
import {mdbInput, mdbBtn, mdbIcon} from 'mdbvue'
import {mapActions,mapGetters} from 'vuex'
import webcam from '../webcam/webcam_Add.vue'
import addClientNew from './new_client_add.vue'
import erpSelect from "../../components/erpSelectFioSearch.vue";  
import erpSelectHisoblar from "../../components/erpSelect.vue";
import erpSelectProduct from "../../components/erpSelectProduct.vue";
import InputSearch from '../../components/inputSearch';
import inputSearchYear from '../../components/inputSearchYear';
import InputSearchTicket from '../../components/inputSearchTicket.vue';
export default {
  components: {
    mdbInput, mdbBtn, mdbIcon,
    erpSelectProduct,
    addClientNew,
    erpSelect,
    InputSearch,
    inputSearchYear,
    InputSearchTicket,
    erpSelectHisoblar,
    webcam
  },
  data() {
    return {
      hostname: this.$store.state.server_ip,
      search: '',
      loading: false,
      modal_status: false,
      modal_info: '',
      showPhoto: false,
      add_client_show: false,
      add_ticket_show: false,
      ticket_data: {
        ticket_number: '',
        massa: 0,
        massa_display: '0',
        price: 0,
        price_display: '0',
        total_price: 0,
        total_price_display: '0',
        organization_name: '',
        tegirmonHisoblar_id: null,
        hisob_name: '',
        note: ''
      },
      hisob_list: [],
      product_list: [
        {
          shafyor_name: '',
          car_number: '',
          shafyor_tel: '',
          note: '',
          product_name: '',
          product_id: null,
          product_price: null,
          all_measure: null,
          car_measure: 0,
          product_measure: 0,
          image_first_pull: '',
          date_first_pull: null,
          pull_status: true,
          auth_first_pull_id: localStorage.AuthId,
          auth_first_pull_name: localStorage.user_name,
        }
      ],
      photo_index: 0,
      client_name: '',
      client_id: null,
      client_info: {},
      passport_number: '',
      born_date: '',
      client_list_last: [],
      selected_ticket_number: '',
      selected_ticket_display: '',
      selected_ticket: null,
    }
  },
  async mounted () {
    await this.fetch_product_t();
    await this.fetch_hikvision_camera_t();
    for(let i=0; i<this.all_product_t.rows.length; i++){
        if(this.all_product_t.rows[i].inv_accepted_status){
          this.product_list[0].product_name = this.all_product_t.rows[i].name;
          this.product_list[0].product_id = this.all_product_t.rows[i].id;
          this.product_list[0].product_price = this.all_product_t.rows[i].price;
        }
      }
      // await this.fetchClient()
      await this.fetchClientLast()
      await this.fetchHisobList()
  },
  computed: {
    ...mapGetters(['all_product_t', 'allClient', 'all_hikvision_camera_t']),
    hasAnyImage() {
      // Agar kamida bitta itemda rasm bo'lsa, true qaytaradi
      return this.product_list.some(item => item.image_first_pull && item.image_first_pull.trim() !== '');
    }
  },
  methods: {
    ...mapActions(['fetch_product_t', 'fetchClient', 'fetch_hikvision_camera_t']),
    async add_client_func(){
      this.add_client_show = !this.add_client_show;
      this.$refs.addClientrefs.MountedFunc();
    },
    async add_invoice_item(){
      let item = {
        shafyor_name: '',
          car_number: '',
          shafyor_tel: '',
          note: '',
          product_name: '',
          product_id: null,
          product_price: null,
          all_measure: null,
          car_measure: 0,
          product_measure: 0,
          image_first_pull: '',
          date_first_pull: null,
          pull_status: true,
          auth_first_pull_id: localStorage.AuthId,
          auth_first_pull_name: localStorage.user_name,
      }
      this.product_list.unshift(item);
      for(let i=0; i<this.all_product_t.rows.length; i++){
        if(this.all_product_t.rows[i].inv_accepted_status){
          this.product_list[0].product_name = this.all_product_t.rows[i].name;
          this.product_list[0].product_id = this.all_product_t.rows[i].id;
          this.product_list[0].product_price = this.all_product_t.rows[i].price;
        }
      }
    },
    async delItem(i){
      this.product_list.splice(i,1);
    },
    async save_items(){
      this.loading = true;
      for(let i=0; i<this.product_list.length; i++){
        await this.save_item_index(i);
      }
      this.loading = false;
      this.$router.push('tarozi_list')
    },
    async save_item_index(index){
      console.log('this.product_list[index]')
      console.log(this.product_list[index])
      const requestOptions = {
        method : "POST",
        headers: { "Content-Type" : "application/json" },
        body: JSON.stringify({
          "shafyor_name" : this.product_list[index].shafyor_name,
          "car_number" : this.product_list[index].car_number,
          "shafyor_tel" : this.product_list[index].shafyor_tel,
          "note": this.product_list[index].note,
          "tegirmonProductid": this.product_list[index].product_id,
          "product_price" : this.product_list[index].product_price,
          "text_1" : this.product_list[index].product_name,
          "image_first_pull": this.product_list[index].image_first_pull,
          "all_measure": this.product_list[index].all_measure,
          "tegirmonClientNewid": this.client_id,
          "tegirmonTicketid": this.selected_ticket ? this.selected_ticket.id : null,
          "text_2": this.client_name,
          "id" : 0,
          "pull_status": this.product_list[index].pull_status,
          "auth_first_pull_id": localStorage.AuthId,
          "auth_first_pull_name": localStorage.user_name,
          "tegirmonAuthid": localStorage.AuthId,
        })
      };
      try{
        this.loading = true;
        const response = await fetch(this.$store.state.hostname + "/TegirmonInvoiceNews", requestOptions);
        this.loading = false;
        if(response.status == 201 || response.status == 200)
        {
          const tryjson = await response.json();
          console.log(tryjson)
          this.$refs.message.success('Added_successfully')
        }
        else{
          const data = await response.text();
          this.modal_info = data;
          this.modal_status = true;
        }
      }
      catch{
        this.loading = false;
        this.modal_info = this.$i18n.t('network_ne_connect'); 
        this.modal_status = true;
      }
    },
    async fetchClientLast(){
          try{
            // this.loading = true;
            const response = await fetch(this.$store.state.hostname + "/TegirmonClientNews/getPagination?page=0&size=100");
            const data = await response.json();
            if(response.status == 201 || response.status == 200)
            {
              this.client_list_last = data.items_list;
              return true;
            }
            else{
              const data_text = await response.text();
              this.modal_info = data_text;
              this.modal_status = true;
              return false;
            }
          }
          catch{
            // this.loading = false;
            this.modal_info = this.$i18n.t('network_ne_connect');
            this.modal_status = true;
          }
        },
    changeInput(index){
      var x = this.product_list[index].shafyor_tel.replace(/\D/g, '').match(/(\d{0,2})(\d{0,3})(\d{0,4})/);
      this.product_list[index].shafyor_tel = !x[2] ? x[1] : '(' + x[1] + ') ' + x[2] + (x[3] ? '-' + x[3] : '');
    },
    selectOptionPro(option){
      console.log(option)
      this.product_list[option.index].product_name = option.data.name;
      this.product_list[option.index].product_id = option.data.id;
      this.product_list[option.index].product_price = option.data.price;
    },
    getPhoto(index_photo){
      this.showPhoto = true;
      this.$refs.camera_component.createCameraElement();
      this.photo_index = index_photo;
    },
    async openCameraSnapshot(index){
      if (!this.all_hikvision_camera_t.rows || this.all_hikvision_camera_t.rows.length === 0) {
        this.$refs.message.warning('please_fill');
        return;
      }
      try{
        const response = await fetch(this.$store.state.hostname + "/TegirmonHikvisionCamera/snapshot_all", {
          method: "POST"
        });
        if(response.status == 201 || response.status == 200)
        {
          const data = await response.json();
          const firstSuccess = Array.isArray(data)
            ? data.find(item => item && item.success && item.image_url)
            : null;
          if (firstSuccess) {
            this.product_list[index].image_first_pull = firstSuccess.image_url;
            this.$refs.message.success('Added_successfully')
          } else {
            this.modal_info = this.$i18n.t('Failed_to_add');
            this.modal_status = true;
          }
        }
        else{
          const data_text = await response.text();
          this.modal_info = data_text;
          this.modal_status = true;
        }
      }
      catch{
        this.modal_info = this.$i18n.t('network_ne_connect'); 
        this.modal_status = true;
      }
    },
    takePhoto(data){
      this.product_list[this.photo_index].image_first_pull = data;
      this.showPhoto = false;
      // this.product_list.push({car_number: 9999});
      // this.product_list.splice(this.product_list.length-1, 1)
    },
    async selectOptionUser(option){
      this.client_info = option;
      this.client_name = option.fio;
      this.client_id = option.id;
      this.passport_number = option.passport_number
      if(option.addiotionala_information){
        this.born_date = option.addiotionala_information.slice(8,10) + '-' + option.addiotionala_information.slice(5,7) + '-' + option.addiotionala_information.slice(0,4);
      }
      // Agar klient tanlangan bo'lsa, ticket tanlangandan olib tashlash
      if (this.selected_ticket) {
        this.clearTicket();
      }
    },
    async selectClientPassport(option){
      this.client_info = option;
      this.client_name = option.fio;
      this.client_id = option.id;
      this.passport_number = option.passport_number
      if(option.addiotionala_information){
        this.born_date = option.addiotionala_information.slice(8,10) + '-' + option.addiotionala_information.slice(5,7) + '-' + option.addiotionala_information.slice(0,4);
      }
      // Agar klient tanlangan bo'lsa, ticket tanlangandan olib tashlash
      if (this.selected_ticket) {
        this.clearTicket();
      }
    },
    async selectClientBorn(option){
      this.client_info = option;
      this.client_name = option.fio;
      this.client_id = option.id;
      this.passport_number = option.passport_number
      if(option.addiotionala_information){
        this.born_date = option.addiotionala_information.slice(8,10) + '-' + option.addiotionala_information.slice(5,7) + '-' + option.addiotionala_information.slice(0,4);
      }
      // Agar klient tanlangan bo'lsa, ticket tanlangandan olib tashlash
      if (this.selected_ticket) {
        this.clearTicket();
      }
    },
    close_clientAdd(option){
      this.add_client_show = false;
      console.log('option')
      console.log(option)
      this.client_info = option;
      this.client_name = option.fio;
      this.client_id = option.id;
      this.passport_number = option.passport_number
      if(option.addiotionala_information){
        this.born_date = option.addiotionala_information.slice(8,10) + '-' + option.addiotionala_information.slice(5,7) + '-' + option.addiotionala_information.slice(0,4);
      }
      // Agar klient tanlangan bo'lsa, ticket tanlangandan olib tashlash
      if (this.selected_ticket) {
        this.clearTicket();
      }
    },
    async fetchHisobList(){
      try{
        const response = await fetch(this.$store.state.hostname + "/TegirmonHisoblar/getPagination?page=0&size=100");
        const data = await response.json();
        if(response.status == 201 || response.status == 200)
        {
          this.hisob_list = data.items_list;
        }
      }
      catch{
        this.hisob_list = [];
      }
    },
    selectHisob(option){
      this.ticket_data.tegirmonHisoblar_id = option.id;
      this.ticket_data.hisob_name = option.name;
    },
    async selectTicket(option){
      console.log('option', option)
      this.selected_ticket = option;
      this.selected_ticket_number = option.ticket_number;
      for(let i=0; i<this.product_list.length; i++){
        this.product_list[i].product_price = option.price;
      }
      // Formatlangan ko'rinish: ticket_number (organization_name)
      let ticketNumber = option.ticket_number || '';
      let orgName = option.organization_name || '';
      if (orgName) {
        this.selected_ticket_display = `${ticketNumber} (${orgName})`;
      } else {
        this.selected_ticket_display = ticketNumber;
      }
      // Ticket tanlanganda, agar kerak bo'lsa, boshqa ma'lumotlarni ham to'ldirish mumkin
      console.log('Selected ticket:', option);
      // Agar ticket tanlangan bo'lsa, klient tanlangandan olib tashlash
      if (this.client_id) {
        this.clearClient();
      }
    },
    formatNumber(value) {
      // Faqat raqamlarni qoldirish
      let numbers = value.replace(/\D/g, '');
      if (numbers === '') return '0';
      // Formatlash: 789000 -> 789 000
      return numbers.replace(/\B(?=(\d{3})+(?!\d))/g, ' ');
    },
    parseNumber(value) {
      // Formatdan tozalash: "789 000" -> 789000
      return parseFloat(value.replace(/\s/g, '')) || 0;
    },
    clearZero(field) {
      if (field === 'massa' && this.ticket_data.massa_display === '0') {
        this.ticket_data.massa_display = '';
      } else if (field === 'price' && this.ticket_data.price_display === '0') {
        this.ticket_data.price_display = '';
      } else if (field === 'total_price' && this.ticket_data.total_price_display === '0') {
        this.ticket_data.total_price_display = '';
      }
    },
    formatMassa(event) {
      let value = event.target.value;
      // Faqat raqam va nuqta qoldirish
      value = value.replace(/[^\d.]/g, '');
      // Bir nechta nuqta bo'lmasligi uchun
      let parts = value.split('.');
      if (parts.length > 2) {
        value = parts[0] + '.' + parts.slice(1).join('');
      }
      // Formatlash
      if (value === '' || value === '.') {
        this.ticket_data.massa_display = '';
        this.ticket_data.massa = 0;
      } else {
        let numValue = parseFloat(value) || 0;
        this.ticket_data.massa = numValue;
        // Butun qismni formatlash
        let intPart = Math.floor(numValue).toString();
        let formatted = this.formatNumber(intPart);
        if (parts.length > 1 && parts[1] && parts[1].length > 0) {
          formatted += '.' + parts[1];
        }
        this.ticket_data.massa_display = formatted;
      }
      
      // Agar price yoki total_price mavjud bo'lsa, qayta hisoblash
      if (this.ticket_data.price > 0 && this.ticket_data.massa > 0) {
        this.ticket_data.total_price = this.ticket_data.price * this.ticket_data.massa;
        this.ticket_data.total_price_display = this.formatNumber(Math.floor(this.ticket_data.total_price).toString());
      } else if (this.ticket_data.total_price > 0 && this.ticket_data.massa > 0) {
        this.ticket_data.price = this.ticket_data.total_price / this.ticket_data.massa;
        this.ticket_data.price_display = this.formatNumber(Math.floor(this.ticket_data.price).toString());
      }
    },
    formatPrice(event) {
      let value = event.target.value;
      // Formatlash
      value = this.formatNumber(value);
      this.ticket_data.price_display = value;
      this.ticket_data.price = this.parseNumber(value);
      
      // total_price ni hisoblash: total_price = price * massa
      if (this.ticket_data.massa > 0 && this.ticket_data.price > 0) {
        this.ticket_data.total_price = this.ticket_data.price * this.ticket_data.massa;
        this.ticket_data.total_price_display = this.formatNumber(Math.floor(this.ticket_data.total_price).toString());
      }
    },
    formatTotalPrice(event) {
      let value = event.target.value;
      // Formatlash
      value = this.formatNumber(value);
      this.ticket_data.total_price_display = value;
      this.ticket_data.total_price = this.parseNumber(value);
      
      // price ni hisoblash: price = total_price / massa
      if (this.ticket_data.massa > 0 && this.ticket_data.total_price > 0) {
        this.ticket_data.price = this.ticket_data.total_price / this.ticket_data.massa;
        this.ticket_data.price_display = this.formatNumber(Math.floor(this.ticket_data.price).toString());
      }
    },
    async save_ticket(){
      if(!this.ticket_data.ticket_number || !this.ticket_data.massa || this.ticket_data.massa === 0){
        alert(this.$i18n.t('please_fill'));
        return;
      }
      this.loading = true;
      // Formatdan tozalangan qiymatlarni olish
      let cleanMassa = this.ticket_data.massa;
      let cleanPrice = this.ticket_data.price || 0;
      let cleanTotalPrice = this.ticket_data.total_price || 0;
      
      const requestOptions = {
        method : "POST",
        headers: { "Content-Type" : "application/json" },
        body: JSON.stringify({
          "ticket_number" : this.ticket_data.ticket_number,
          "massa" : cleanMassa,
          "price": cleanPrice,
          "total_price": cleanTotalPrice,
          "organization_name": this.ticket_data.organization_name || '',
          "tegirmonHisoblar_id": this.ticket_data.tegirmonHisoblar_id,
          "hisob_name": this.ticket_data.hisob_name || '',
          "note": this.ticket_data.note || '',
          "tegirmonAuthId": localStorage.AuthId ? parseInt(localStorage.AuthId) : null,
          "id" : 0,
          "active_status": true
        })
      };
      try{
        const response = await fetch(this.$store.state.hostname + "/TegirmonTicket", requestOptions);
        this.loading = false;
        if(response.status == 201 || response.status == 200)
        {
          const tryjson = await response.json();
          console.log(tryjson)
          this.add_ticket_show = false;
          // Reset form
          this.ticket_data = {
            ticket_number: '',
            massa: 0,
            massa_display: '0',
            price: 0,
            price_display: '0',
            total_price: 0,
            total_price_display: '0',
            organization_name: '',
            tegirmonHisoblar_id: null,
            hisob_name: '',
            note: ''
          };
          this.$refs.message.success('Added_successfully')

        }
        else{
          const data = await response.text();
          this.modal_info = data;
          this.modal_status = true;
        }
      }
      catch{
        this.loading = false;
        this.modal_info = this.$i18n.t('network_ne_connect'); 
        this.modal_status = true;
      }
    },
    clearClient() {
      // Klient ma'lumotlarini tozalash
      this.client_info = {};
      this.client_name = '';
      this.client_id = null;
      this.passport_number = '';
      this.born_date = '';
      // Search komponentlarini tozalash
      if (this.$refs.search_client) {
        this.$refs.search_client.clear();
      }
      if (this.$refs.search_client_born_date) {
        this.$refs.search_client_born_date.clear();
      }
    },
    clearTicket() {
      // Ticket ma'lumotlarini tozalash
      this.selected_ticket = null;
      this.selected_ticket_number = '';
      this.selected_ticket_display = '';
      // Product listdagi price larni tozalash
      for(let i=0; i<this.product_list.length; i++){
        this.product_list[i].product_price = null;
      }
      // Search komponentini tozalash
      if (this.$refs.search_ticket) {
        this.$refs.search_ticket.clear();
      }
    }
  },
}
</script>

